package orchestration

import (
	"github.com/kastheco/kasmos/config/taskparser"
)

// WaveState represents the current state of wave orchestration for a plan.
type WaveState int

const (
	WaveStateIdle         WaveState = iota // Not started
	WaveStateElaborating                   // Waiting for elaborator to enrich task descriptions
	WaveStateRunning                       // Current wave's tasks are running
	WaveStateWaveComplete                  // Current wave finished, awaiting user confirmation
	WaveStateAllComplete                   // All waves finished
)

// taskStatus tracks the completion state of a single task.
type taskStatus int

for planFile, tasks := range byPlan {
	// Skip if orchestrator already exists.
	if _, exists := m.waveOrchestrators[planFile]; exists {
		continue
	}
	// Only reconstruct for implementing plans.
	entry, ok := m.taskState.Entry(planFile)
	if !ok || entry.Status != taskstate.StatusImplementing {
		continue
	}

	// Parse the plan content from store.
	content, err := m.taskStore.GetContent(m.taskStoreProject, planFile)
	if err != nil {
		log.WarningLog.Printf("rebuildOrphanedOrchestrators: cannot read %s: %v", planFile, err)
		continue
	}
	plan, err := taskparser.Parse(content)
